const raw = String($json.choices?.[0]?.message?.content || '').trim();
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('LLM_PARSE_ERROR: ' + e.message);
}

if (!parsed.script) throw new Error('LLM_MISSING_FIELD: script');
if (!parsed.caption) throw new Error('LLM_MISSING_FIELD: caption');
if (!parsed.hook) throw new Error('LLM_MISSING_FIELD: hook');

return [{ json: { script: parsed.script, caption: parsed.caption, hook: parsed.hook, background_keyword: parsed.background_keyword || '' } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($('Normalize Output').item.json.workflowRunId || 0);
const contentIdeaId = Number($('Normalize Output').item.json.contentIdeaId || 0);
const scriptLength = ($('Normalize Output').item.json.script || '').length;

if (!baseUrl || !callbackSecret || !workflowRunId) {
  throw new Error('Missing callback config');
}

const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: 'Script generation complete.',
  responsePayload: JSON.stringify({ contentIdeaId, scriptLength })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

let attempts = 0;
const maxAttempts = 2;

const makeRequest = () => {
  return new Promise((resolve, reject) => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      res.on('data', () => {});
      res.on('end', () => resolve({ statusCode: res.statusCode || 0 }));
    });

    req.on('error', (err) => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(() => makeRequest().then(resolve).catch(reject), Math.pow(2, attempts) * 1000);
      } else {
        reject(err);
      }
    });

    req.setTimeout(10000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(() => makeRequest().then(resolve).catch(reject), Math.pow(2, attempts) * 1000);
      } else {
        reject(new Error('Callback timeout'));
      }
    });

    req.write(body);
    req.end();
  });
};

const response = await makeRequest();
if (response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error('Success callback failed: ' + response.statusCode);
}

return [{ json: { ok: true, statusCode: response.statusCode, contentIdeaId, workflowRunId } }];

const contentIdeaId = Number($('Extract Input')?.item?.json?.contentIdeaId || 0);
const workflowRunId = Number($('Extract Input')?.item?.json?.workflowRunId || 0);
const error = $json;
let errorMsg = 'Input validation failed';

if (typeof error === 'string' && error.trim()) {
  errorMsg = error;
} else if (error?.message) {
  errorMsg = String(error.message);
} else if (error?.error) {
  errorMsg = String(error.error);
} else if (error && (error.contentIdeaId || error.topic || error.category || error.workflowRunId)) {
  errorMsg = 'Input validation failed';
}

return [{ json: { contentIdeaId, workflowRunId, error: errorMsg, error_at: new Date().toISOString() } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const workflowRunId = Number($json.workflowRunId || 0);
const contentIdeaId = Number($json.contentIdeaId || 0);
const errorMsg = String($json.error || 'Unknown error');

if (!baseUrl || !callbackSecret || !workflowRunId) {
  return [{ json: { ok: false, error: errorMsg, statusCode: 0 } }];
}

const body = JSON.stringify({
  status: 'FAILED',
  message: 'Script generation failed: ' + errorMsg.slice(0, 200),
  responsePayload: JSON.stringify({ contentIdeaId, error: errorMsg.slice(0, 500) })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;

let attempts = 0;
const maxAttempts = 2;

const makeRequest = () => {
  return new Promise((resolve) => {
    const req = client.request({
      protocol: url.protocol,
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + url.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(body),
        'X-Video-Ops-Callback-Secret': callbackSecret,
        'X-Request-Timestamp': Date.now().toString()
      }
    }, (res) => {
      res.on('data', () => {});
      res.on('end', () => resolve({ statusCode: res.statusCode || 0 }));
    });

    req.on('error', () => {
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(() => makeRequest().then(resolve), Math.pow(2, attempts) * 1000);
      } else {
        resolve({ statusCode: 0, error: 'Request failed' });
      }
    });

    req.setTimeout(10000, () => {
      req.destroy();
      attempts++;
      if (attempts < maxAttempts) {
        setTimeout(() => makeRequest().then(resolve), Math.pow(2, attempts) * 1000);
      } else {
        resolve({ statusCode: 0, error: 'Timeout' });
      }
    });

    req.write(body);
    req.end();
  });
};

const response = await makeRequest();
return [{ json: { ok: response.statusCode >= 200 && response.statusCode < 300, statusCode: response.statusCode, error: errorMsg, contentIdeaId, workflowRunId } }];

